command.text:
declare @message nvarchar(4000) select @message = ''
&CommandControlLocationLotShowing;
select @message as message return

script.text:

function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    gia_nt2_sl: '[gia_nt2]:=([gia_nt2] == 0 ? ([so_luong] != 0 ? ([tien_nt2]/[so_luong]) : 0) : [gia_nt2])',
    gia2_sl: '[gia2]:=([gia2] == 0 ? ([so_luong] != 0 ? ([tien2]/[so_luong]) : 0) : [gia2])',

    gia2_tg: '[gia2]:=[gia_nt2]*[$ty_gia]',
    tien_nt2: '[tien_nt2]:=[so_luong]*[gia_nt2]',
    tien2: '[tien2]:=[so_luong]*[gia2]',
    tien2_tg: '[tien2]:=[tien_nt2]*[$ty_gia]',

    &DetailTaxFomula;

    t_tien_nt2: ['t_tien_nt2', 'tien_nt2'],
    t_tien2: ['t_tien2', 'tien2'],

    t_thue: '[t_thue]:=[t_tien2]*[thue_suat]/100',
    t_thue_nt: '[t_thue_nt]:=[t_tien_nt2]*[thue_suat]/100',

    t_tt_nt: '[t_tt_nt]:=[t_tien_nt2]+[t_thue_nt]',
    t_tt: '[t_tt]:=[t_tien2]+[t_thue]'
  };
  g.$h = [['voucherCode', 'String', g._voucherCode], 'ma_kh', 'ngay_lct', 'ma_tt', 'loai_ct', 'ma_nt', 'ma_dvcs'];
  udf$Detail$(g);
}
/* <flatten type="Javascript"> */
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
}
function onChange$GridVoucherDetail$Item(o) {o.grid.request(o, 'Item', 'Item', ['ma_vt', 'ma_kho'], o.grid.$h, true);}
function onChange$GridVoucherDetail$UOM(o) {o.grid.request(o, 'UOM', 'UOM', ['ma_vt', 'ma_kho', 'dvt', 'so_luong'], o.grid.$h, true);}
function onChange$GridVoucherDetail$Site(o) {o.grid.request(o, 'Site', 'Site', ['ma_vt', 'ma_kho', 'loai_ct'], o.grid.$h, true);}
function onChange$GridVoucherDetail$ReferenceAccount(o) {o.grid.request(o, 'RefAccount', 'RefAccount', ['tk_du'], o.grid.$h, true);}
/* </flatten> */
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'so_luong':
      g.validExpression(o, [g.$a.tien_nt2, g.$a.AmountFormula], null, null, 'gia_nt2');
      on$GridVoucherDetail$AmountChange(o, g, f);
      on$GridVoucherDetail$TaxChange(o, g, f);
      break;
    case 'gia_nt2':
      g.validExpression(o, [g.$a.gia2_tg, g.$a.tien_nt2, g.$a.AmountFormula], null, null, 'tien_nt2');
      on$GridVoucherDetail$AmountChange(o, g, f);
      on$GridVoucherDetail$TaxChange(o, g, f);
      break;
    case 'gia2':
      &DetailTaxValidSalesPrice;
      break;
    case 'tien_nt2':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_nt2_sl, g.$a.gia2_tg]);
      g.validExpression(o, [g.$a.tien2_tg], null, null);
      on$GridVoucherDetail$AmountChange(o, g, f);
      on$GridVoucherDetail$TaxChange(o, g, f);
      break;
    case 'tien2':
      if (f._calPrice) g.validExpression(o, [g.$a.gia2_sl]);
      &DetailTaxValidSalesAmount;
      break;
    &DetailTaxOnchange;
    default:
      break;
  }
}
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {&ScriptCheckGridAction;
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterInsertRow':
      &DetailTaxGridAfterInsertRow;
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'Check':
      if (g._tracked$Lot && !(g.validRowExpression('ma_lo', '(![lo_yn]) || ([ma_lo] != "")'))) break;
      if (g._tracked$Location && !(g.validRowExpression('ma_vi_tri', '(![vi_tri_yn]) || ([ma_vi_tri] != "")'))) break;
      &DetailTaxExecuteCommandCheckAuthority;
      break;
    case 'Retrieve':
      if (f._action == 'View') break;
      if (!f.validFields('ma_kh, ngay_lct')) break;
      if (f._action != 'View') g.showForm('SPInvoiceFilter');
      break;
    case 'Copying':
      set$Voucher$EmptyExternalField(g, 'hd_so, hd_ln, stt_rec_hd, stt_rec0hd');
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'Item':
      var v = (result[0].Value == '' ? true : null), t = (result[0].Value == '' ? 'false' : 'true');
      var u = (f.getItem('loai_ct').value == '2');
      var a = (u ? result[12].Value : result[14].Value), b = (u ? result[13].Value : result[15].Value);
      g.setItemGridBehavior(o, [
        ['ma_lo', '', null, null],
        ['ma_kho', result[0].Value, '', true],
        ['ma_vi_tri', result[1].Value, '', v],
        ['dvt', result[2].Value, '', true],
        ['he_so', result[3].Value, null, null],
        ['tk_du', a, ['', b], true],
        ['tk_vt', result[5].Value, '', true],
        ['gia_ton', result[6].Value, null, null],
        ['vi_tri_yn', [result[7].Value, t], null, null],
        ['lo_yn', result[8].Value, null, null],
        ['tk_dt', result[12].Value, null, null],
        ['kieu_dt', result[13].Value, null, null],
        ['tk_gghb', result[14].Value, null, null],
        ['kieu_gg', result[15].Value, null, null]
      ]);
      &DetailTaxResponseCompleteItem;
      g.live(o, 'dvt');
      break;
    case 'UOM':
      g.setItemGridBehavior(o, [['he_so', result[0].Value, '', true]]);
      break;
    case 'Site':
      g.setItemGridBehavior(o, [['tk_vt', result[0].Value, '', true], ['ma_vi_tri', '', '', null], ['vi_tri_yn', result[1].Value, null, null]]);
      break;
    case 'RefAccount':
      var u = (f.getItem('loai_ct').value == 2);
      if (result[0].Value) {
        var s = result[1].Value;
        if (s) g.setItemGridBehavior(o, [[u ? 'tk_dt' : 'tk_gghb', s, null, null], [u ? 'kieu_dt' : 'kieu_gg', result[0].Value, null, null]]);
      }
      break;
    &DetailTaxResponseComplete;
    default:
      break;
  }
}
function on$GridVoucherDetail$RowChange(g, f) {
  &DetailTaxValidRowChange;
}
/* <flatten type="Javascript"> */
function on$GridVoucherDetail$AmountChange(o, g, f) {g.executeAggregate([g.$a.t_tien_nt2, g.$a.t_tien2]);}
/* </flatten> */
function on$GridVoucherDetail$TaxChange(o, g, f) {
  &DetailTaxValidTaxChange;
}

      &ScriptInsertRetrieveItems;
      &ScriptEmptyExternalField;

grid.response:
&XMLGetUOMConversion;
if exists(select 1 from dmvt where ma_vt = @ma_vt) begin declare @unitCode varchar(32) select @unitCode = case when @$ma_dvcs = '' then @@unit else @$ma_dvcs end exec FastBusiness$Voucher$SalesPriceAdjustment$Item @unitCode, @ma_vt, @$loai_ct, @voucherCode, @@userID, @@admin, @ma_kho, &DetailTaxFlag; return end
declare @unitCode varchar(32) select @unitCode = case when @$ma_dvcs = '' then @@unit else @$ma_dvcs end if exists(select 1 from dmkho where ma_kho = @ma_kho and ma_dvcs = @unitCode&SiteCheck;) begin exec FastBusiness$Voucher$Receipt$Site @unitCode, @ma_vt, @ma_kho return end
select rtrim(loai_tk), rtrim(tk) from dmtk where tk = @tk_du return
&DetailTaxGetTaxRate; &DetailTaxGetTaxAccount;
